    @subtotal_exento = {{ Number(String(inpSTnoGravadoNC.text || "0").replace(/,/g, "")) }},
    @porcentaje_itbis = {{ Number(selPorcentajeItbisNC.selectedOptionValue || 0) }},
    @monto_itbis = {{ Number(String(inpITBIS_NC.text || "0").replace(/,/g, "")) }},
    @monto_total = {{ Number(String(inpTotalNC.text || "0").replace(/,/g, "")) }},
    @concepto = {{ inpConceptoNC.text }},
    @comentarios = {{ inpComentarioNC.text }},
    @ncf = {{ inpNCF_NC.text }},
    @codigo_seguridad = {{ inpCodigoDeSeguridadNC.text }};
